// Test: null wave data (inland) should still produce valid result
async function testComputeSeaStatusNullWaves() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 10,
    windGusts: 14,
    waveHeight: null,   // no marine data — inland position
    precipitation: 0,
    pressure: 1013,
    cloudCover: 40
  });

  assert(result.level !== undefined, 'Should have a level even without wave data');
  assert(result.score >= 0 && result.score <= 100, 'Score should be 0-100, got ' + result.score);
  assert(typeof result.label === 'string', 'Label should be a string');
  assert(Array.isArray(result.reasons), 'Reasons should be an array');
  // Without waves to penalize, light wind should be green
  assertEquals(result.level, 'green', 'Light wind with no waves should be green');
}
